#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Deploy parallel email-crawler fleet (exit-0-safe) — deploy FIRST, measure later.
10 looping workers running the proven crawler, db.env only (no status spam)."""
import os,sys,json,time,subprocess
N=10
UNIT="/etc/systemd/system/atlas-deepcrawl-pool@.service"
BODY="""[Unit]
Description=ATLAS email crawler pool worker %i
After=postgresql.service
Wants=postgresql.service

[Service]
Type=simple
EnvironmentFile=-/etc/atlas/db.env
Environment=DEEPCRAWL_BATCH=5
ExecStart=/bin/bash -c 'while true; do /opt/atlas/venv/bin/python /opt/atlas/importers/atlas_email_deepcrawl.py >/dev/null 2>&1 || true; sleep 4; done'
Restart=always
RestartSec=5
Nice=10

[Install]
WantedBy=multi-user.target
"""
def sh(c,t=40):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception as e: return "ERR:%s"%e
out={"kind":"fleet","ver":2,"ts":int(time.time()),"workers":N}
# DEPLOY FIRST (most important)
try:
    open(UNIT,"w").write(BODY)
    out["daemon_reload"]=sh("systemctl daemon-reload 2>&1; echo rc=$?")
    insts=" ".join("atlas-deepcrawl-pool@%d.service"%i for i in range(1,N+1))
    out["enable"]=sh("systemctl enable --now %s 2>&1 | tail -2"%insts, t=60)
    out["active_count"]=sh("systemctl list-units 'atlas-deepcrawl-pool@*.service' --state=active --no-legend --plain 2>/dev/null | wc -l")
except Exception as e:
    out["deploy_error"]=str(e)
# measure (best-effort, short timeout, fast queries only)
try:
    r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc","SELECT count(*)||'/'||current_setting('max_connections') FROM pg_stat_activity"],capture_output=True,text=True,timeout=15)
    out["pg_conns"]=r.stdout.strip() if r.returncode==0 else "ERR"
except Exception as e: out["pg_conns"]="TO"
try:
    r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc","SELECT count(*) FROM atlas.business WHERE application_name IS NULL LIMIT 1"],capture_output=True,text=True,timeout=5)
except Exception: pass
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/fleet.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"fleet2","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(4):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
